insert into public.courses (slug, title, category, description, duration, is_published)
values ('ia-educativa-notebooklm', 'Programa de Inteligencia Artificial Aplicada a la Educación con NotebookLM', 'IA educativa', 'Un recorrido profesional para comprender, aplicar y verificar inteligencia artificial en aprendizaje, docencia e investigación usando NotebookLM como eje metodológico.', '11 módulos · 22 horas sugeridas', true)
