modulo-7-guia-de-estudio","title":"Actividad: guía de estudio verificable","lesson_order":3,"lesson_type":"activity","summary":"Construir una guía de estudio con preguntas, respuestas y referencias a fuentes."},{"module_slug":"modulo-8-notebooklm-para-docentes","slug":"modulo-8-rol-docente-era-ia","title":"El nuevo rol docente en la era de la IA","lesson_order":1,"lesson_type":"theory","summary":"La IA como apoyo para diseñar mejores experiencias sin reemplazar criterio profesional."},{"module_slug":"modulo-8-notebooklm-para-docentes","slug":"modulo-8-planificar-clases-con-notebooklm","title":"Planificar clases con NotebookLM","lesson_order":2,"lesson_type":"theory","summary":"Fuentes, objetivo, diseño, clase, evaluación y mejora como secuencia docente."},{"module_slug":"modulo-8-notebooklm-para-docentes","slug":"modulo-8-secuencia-didactica","title":"Actividad: secuencia didáctica","lesson_order":3,"lesson_type":"activity","summary":"Diseñar una clase con materiales, preguntas, evaluación y verificación."},{"module_slug":"modulo-9-investigacion-academica-asistida","slug":"modulo-9-investigar-en-la-era-de-la-ia","title":"Investigar en la era de la IA","lesson_order":1,"lesson_type":"theory","summary":"La IA apoya la investigación, pero el producto final debe mostrar comprensión."},{"module_slug":"modulo-9-investigacion-academica-asistida","slug":"modulo-9-flujo-de-investigacion","title":"Flujo de investigación","lesson_order":2,"lesson_type":"theory","summary":"Delimitar, reunir, explorar, comparar, sintetizar y verificar fuentes académicas."},{"module_slug":"modulo-9-investigacion-academica-asistida","slug":"modulo-9-matriz-de-investigacion","title":"Actividad: matriz de investigación","lesson_order":3,"lesson_type":"activity","summary":"Construir una matriz con autores, ideas, evidencias y síntesis propia."},{"module_slug":"modulo-10-proyecto-final-aplicado","slug":"modulo-10-sentido-del-proyecto-final","title":"Sentido del proyecto final","lesson_order":1,"lesson_type":"project","summary":"Integrar problema, fuentes, NotebookLM, verificación, producto y defensa."},{"module_slug":"modulo-10-proyecto-final-aplicado","slug":"modulo-10-arquitectura-del-proyecto","title":"Arquitectura del proyecto","lesson_order":2,"lesson_type":"project","summary":"Definir problema, producto parcial, evidencia y modalidad según perfil."},{"module_slug":"modulo-10-proyecto-final-aplicado","slug":"modulo-10-defensa-del-proyecto","title":"Evaluación: defensa del proyecto","lesson_order":3,"lesson_type":"assessment","summary":"Preparar una defensa breve con decisiones, fuentes, límites y aprendizaje construido."},{"module_slug":"modulo-11-actualizacion-permanente","slug":"modulo-11-lo-que-cambia-y-lo-que-permanece","title":"Lo que cambia y lo que permanece","lesson_order":1,"lesson_type":"theory","summary":"Herramientas cambian; criterio, fuentes, verificación y ética deben conservarse."},{"module_slug":"modulo-11-actualizacion-permanente","slug":"modulo-11-aprendiz-estrategico","title":"De usuario de herramientas a aprendiz estratégico","lesson_order":2,"lesson_type":"theory","summary":"Observar, comprender, probar, verificar, integrar y enseñar."},{"module_slug":"modulo-11-actualizacion-permanente","slug":"modulo-11-plan-de-actualizacion","title":"Evaluación: plan de actualización","lesson_order":3,"lesson_type":"assessment","summary":"Diseñar una rutina realista para seguir aprendiendo IA con evidencia y criterio."}]}'::jsonb as value)
insert into public.lessons (module_id, slug, title, lesson_order, lesson_type, summary, content, is_published)
select m.id, item.slug, item.title, item.lesson_order, item.lesson_type, item.summary, item.summary, true
from payload, jsonb_to_recordset(payload.value -> 'lessons') as item(module_slug text, slug text, title text, lesson_order integer, lesson_type text, summary text)
join public.modules m on m.slug = item.module_slug
on conflict (slug) do update set title = excluded.title, lesson_order = excluded.lesson_order, lesson_type = excluded.lesson_type, summary = excluded.summary, content = excluded.content, is_published = true;

